    def _request_keybind(self):
        """Tell parent to listen for a key to bind to hide/show this window."""
        pw = self.parent_win
        if pw.waiting_for_key:
            return None
        else:
            pw.waiting_for_key = 'hide_info'
            self._set_keybind_waiting()
    def _set_keybind_waiting(self):
        self._kb_hide_btn.setText('...')
        self._kb_hide_btn.setIcon(QIcon())
        self._kb_hide_btn.setStyleSheet('QPushButton { background: #2a2a44; color: #AAAAFF; border: 1px solid #5555aa; border-radius: 4px; }QPushButton:hover { background: #333355; }')
        self._kb_hide_btn.setToolTip('Press any key... (ESC to cancel)')
    def _set_keybind_bound(self, vk):
        if vk is None or vk == (-1):
            self._kb_hide_btn.setText('')
            self._kb_hide_btn.setIcon(_make_kb2_icon(18))
            self._kb_hide_btn.setIconSize(QSize(18, 18))
            self._kb_hide_btn.setToolTip('Bind a key to toggle this window')
            self._kb_hide_btn.setStyleSheet('QPushButton { background: #1C2333; color: #8B949E; border: 1px solid #21262D; border-radius: 4px; }QPushButton:hover { background: #1F8EF133; color: #E6EDF3; border-color: #1F8EF1; }QPushButton:pressed { background: #0D1117; }')
        else:
            label = get_key_name(vk)
            self._kb_hide_btn.setIcon(QIcon())
            self._kb_hide_btn.setText(label)
            self._kb_hide_btn.setToolTip(f'Toggle key: {label}  (click to rebind)')
            self._kb_hide_btn.setStyleSheet('QPushButton { background: #1a2a1a; color: #88FF88; border: 1px solid #3a6a3a; border-radius: 4px; font-family: Consolas; font-size: 8pt; font-weight: bold; }QPushButton:hover { background: #224422; border-color: #66aa66; }QPushButton:pressed { background: #111f11; }')
    def _toggle_collapse(self):
        self._collapsed = not self._collapsed
        if self._collapsed:
            self._expanded_height = self.height()
            self._scroll_area.setVisible(False)
            self.setFixedHeight(self._title_bar_height + self._bottom_bar_height)
        else:
            self.setMinimumHeight(200)
            self.setMaximumHeight(16777215)
            self._scroll_area.setVisible(True)
            self.resize(self.width(), self._expanded_height)
    def mousePressEvent(self, e):
        if e.button() == Qt.LeftButton:
            self._drag_pos = e.globalPos() - self.frameGeometry().topLeft()
    def mouseMoveEvent(self, e):
        if e.buttons() == Qt.LeftButton and self._drag_pos is not None:
                self.move(e.globalPos() - self._drag_pos)
    def mouseReleaseEvent(self, e):
        self._drag_pos = None
    def refresh(self):
        """Pull current values from the parent SigmaWindow and update labels."""
        pw = self.parent_win
        def _bool(val, true_col='#44FF88', false_col='#FF4444'):
            if val:
                return ('ON', true_col)
            else:
                return ('OFF', false_col)
        def _set(key, text, color='#888888'):
            w = self._stat_widgets.get(key)
            if w:
                w.setText(str(text))
                w.setStyleSheet(f'color: {color}; background: transparent; font-weight: bold;')
        for attr, _ in self.ROWS:
            val_lbl = self._row_widgets[attr]
            raw = getattr(pw, attr, None)
            if raw is None:
                text, color = ('—', '#333333')
            else:
                text = str(raw).upper() if attr == 'sigbot_key2press' else get_key_name(raw)
                color = '#FFFFFF'
            val_lbl.setText(text)
            val_lbl.setStyleSheet(f'color: {color}; background: transparent; font-weight: bold;')
        t, c = _bool(getattr(pw, 'macro_system_enabled', False))
        _set('sys_active', t, c)
        t, c = _bool(getattr(pw, 'toggled', False))
        _set('macro_active', t, c)
        t, c = _bool(getattr(pw, 'mouse_locked', False))
        _set('mouse_locked', t, c)
        action_mode = getattr(pw, 'action_mode', 'kps').upper()
        rate = getattr(pw, 'cps', 0)
        _set('rate', f'{rate}', '#FFFFFF')
        _set('mode', getattr(pw, 'mode', 'toggle').capitalize(), '#CCCCCC')
        _set('action', action_mode, '#AADDFF')
        wm = getattr(pw, 'window_mode', 'roblox')
        _set('target', 'Roblox' if wm == 'roblox' else 'Global', '#FFDDAA')
        mb = getattr(pw, 'mouse_button', 'left').capitalize()
        _set('mouse_btn', mb, '#DDAAFF')
        t, c = _bool(getattr(pw, 'randomize_angles', False))
        _set('randomize', t, c)
        cd = getattr(pw, 'flick_cooldown', 0.0)
        _set('flick_cd', f'{cd:.2f}s', '#AAAAAA')
        _set('flick_b', str(getattr(pw, 'fspeed_backward', 0)), '#88AAFF')
        _set('flick_l', str(getattr(pw, 'fspeed_lside', 0)), '#88AAFF')
        _set('flick_r', str(getattr(pw, 'fspeed_rside', 0)), '#88AAFF')
        _set('chance_v', f'{getattr(pw, 'chance_vertical', 0)}%', '#AAFFAA')
        _set('chance_b', f'{getattr(pw, 'chance_backward', 0)}%', '#AAFFAA')
        _set('chance_l', f'{getattr(pw, 'chance_lside', 0)}%', '#AAFFAA')
        _set('chance_r', f'{getattr(pw, 'chance_rside', 0)}%', '#AAFFAA')
        t, c = _bool(getattr(pw, 'sigbot_enabled', False))
        _set('sigbot_active', t, c)
        t, c = _bool(getattr(pw, 'sigbot_hold_mode', False))
        _set('sigbot_hold', t, c)
        sc = getattr(pw, 'sigbot_target_color', (1, 121, 120))
        if sc:
            r, g, b = sc
            hex_str = f'{r:02X}{g:02X}{b:02X}'
            _set('sig_color', f'#{hex_str}', f'#{hex_str}')
            sw = self._color_swatches.get('sig_color')
            if sw:
                sw.setStyleSheet(f'background: #{hex_str}; border-radius: 3px; border: 1px solid #666666;')
        _set('tolerance', str(getattr(pw, 'sigbot_tolerance', 0)), '#FFCC88')
        _set('reaction', f'{getattr(pw, 'sigbot_reaction_ms', 0)}ms', '#FFCC88')
        _set('press_cd', f'{getattr(pw, 'sigbot_cooldown_ms', 0)}ms', '#FFCC88')
