    def _on_comp_system_toggled(self, armed):
        """Called when comp_system key arms/disarms the macro 2 system."""
        self.comp_system_enabled = armed
        if not armed and self.comp_active:
                self.comp_active = False
                try:
                    self._update_comp_status_icon()
                except RuntimeError:
                    pass
        self._refresh_status_icon()
        self._update_info_window()
    def _toggle_competitive(self):
        """Start or stop the comp_active running state only.\nThe macro2_enabled gate is handled separately by the UI button."""
        if self.comp_active:
            self.comp_active = False
            try:
                self.comp_live_val.setText('0')
            except:
                pass
            try:
                self._update_comp_status_icon()
            except RuntimeError:
                pass
            self._refresh_status_icon()
            self._update_info_window()
            return None
        else:
            if self.comp_action_mode == 'cps':
                if self.comp_key2spam is None or self.comp_key2spam not in [1, 2, 4, 5, 6]:
                    return None
            else:
                if self.comp_action_mode == 'merged':
                    if self.comp_key2spam is None:
                        return None
            if self._comp_thread and self._comp_thread.isRunning():
                    return None
            self.comp_active = True
            try:
                self.comp_live_val.setText('0')
            except:
                pass
            self._comp_thread = CompetitiveModeThread(self)
            self._comp_thread.cps_updated.connect(self._on_comp_cps_updated)
            self._comp_thread.start()
            try:
                self._update_comp_status_icon()
            except RuntimeError:
                pass
            self._refresh_status_icon()
            self._update_info_window()
    def _on_comp_cps_updated(self, value):
        """Called from CompetitiveModeThread when the ramped CPS changes."""
        try:
            self.comp_live_val.setText(str(value))
            self.cps = value
            self.kps_entry.blockSignals(True)
            self.kps_slider.blockSignals(True)
            self.kps_entry.setText(str(value))
            self.kps_slider.setValue(min(value, 5000))
            self.kps_entry.blockSignals(False)
            self.kps_slider.blockSignals(False)
            self._update_info_window()
        except RuntimeError:
            return None
